const body = $input.first().json.body || $input.first().json;
const event = body.event;
if (event === 'messages.upsert') {
  const msg = body.data; 
  const key = msg.key;
  const phone = key.remoteJid?.split('@')[0]?.split(':')[0] || '';

  let content = '';
  let contentType = 'text';
  let mimeType = 'application/octet-stream';

  if (msg.message?.conversation) {
    content = msg.message.conversation;
  } else if (msg.message?.extendedTextMessage?.text) {
    content = msg.message.extendedTextMessage.text;
  } else if (msg.message?.imageMessage) { 
    content = msg.message.imageMessage.caption || '[Imagem]'; 
    contentType = 'image'; 
    mimeType = msg.message.imageMessage.mimetype || 'image/jpeg';
  } else if (msg.message?.audioMessage) { 
    content = '[Áudio]'; 
    contentType = 'audio'; 
    mimeType = msg.message.audioMessage.mimetype || 'audio/ogg';
  } else if (msg.message?.videoMessage) { 
    content = msg.message.videoMessage.caption || '[Vídeo]'; 
    contentType = 'video'; 
    mimeType = msg.message.videoMessage.mimetype || 'video/mp4';
  } else if (msg.message?.documentMessage) { 
    content = msg.message.documentMessage.fileName || '[Documento]'; 
    contentType = 'document'; 
    mimeType = msg.message.documentMessage.mimetype || 'application/pdf';
  } else if (msg.message?.stickerMessage) { 
    content = '[Figurinha]'; 
    contentType = 'sticker'; 
    mimeType = msg.message.stickerMessage.mimetype || 'image/webp';
  } else {
    content = '[Mensagem não suportada]';
  }

  return [{ 
    json: { 
      event_type: 'message.received', 
      whatsapp_msg_id: key.id, 
      phone, 
      contact_name: msg.pushName || phone, 
      direction: key.fromMe ? 'out' : 'in', 
      content, 
      content_type: contentType, 
      media_url: null, 
      mime_type: mimeType,
      timestamp: new Date(msg.messageTimestamp*1000).toISOString(), 
      instance: body.instance,
      is_media: ['image', 'audio', 'video', 'document', 'sticker'].includes(contentType),
      raw_key: key,
      raw_message: msg.message
    } 
  }];
} else {
  return [{ json: { event_type: 'skip', reason: 'Not a message: ' + event } }];
}

const settings = $('Fetch AI Settings').first()?.json;
if (!settings) {
  return [{ json: { run_ai: false, reason: 'No settings found' } }];
}

// Retrieve contact tags
let contact = {};
try {
  contact = $('Upsert Contact').first().json;
} catch(e) {
  try {
    contact = $input.first().json; // fallback
  } catch(err) {}
}

const tags = contact.tags || [];
const isPausedByTag = tags.includes('IA Inativa');

// Read columns directly from Supabase settings row
const isEnabledGlobal = settings.is_enabled === true;
const systemPrompt = settings.system_prompt || '';
const negativePrompt = settings.negative_prompt || '';
const apiKey = settings.api_key || '';
const model = settings.model || 'gpt-4o-mini';
const temperature = settings.temperature ?? 0.7;

// Find message info dynamically
let msgText = '';
let direction = 'in';
let phone = contact.phone || '';

try {
  const parsed = $('Parse Evolution Payload').first().json;
  msgText = parsed.content || '';
  direction = parsed.direction || 'in';
  if (!phone) phone = parsed.phone || '';
} catch(e) {}

const isInbound = direction === 'in';

// Check pause trigger phrases
const pausePhrases = settings.pause_trigger_phrases || [];
const matchedPhrase = pausePhrases.find(p => msgText.toLowerCase().includes(p.toLowerCase()));

let pauseBot = false;
let runAi = false;
let reason = '';

if (!isEnabledGlobal) {
  reason = 'AI is disabled globally';
} else if (!isInbound) {
  reason = 'Message is outbound';
} else if (isPausedByTag) {
  reason = 'AI is paused for this contact (IA Inativa tag present)';
} else if (matchedPhrase) {
  pauseBot = true;
  reason = `AI paused by trigger phrase: "${matchedPhrase}"`;
} else {
  runAi = true;
  reason = 'All checks passed, running AI';
}

const updatedTags = isPausedByTag ? tags : [...tags, 'IA Inativa'];

return [{
  json: {
    run_ai: runAi,
    pause_bot: pauseBot,
    reason: reason,
    contact_id: contact.id,
    phone: phone,
    user_message: msgText,
    system_prompt: systemPrompt,
    negative_prompt: negativePrompt,
    api_key: apiKey,
    model: model,
    temperature: temperature,
    updated_tags: updatedTags
  }
}];

const msgs = $input.all().map(item => item.json);
const inboundMsgs = msgs.filter(m => m.direction === 'in');
const routerData = $('AI Routing Decision').first().json;
const welcomeMessage = routerData.welcome_message || '';

if (inboundMsgs.length <= 1 && welcomeMessage.trim() !== '') {
  return [{
    json: {
      is_welcome: true,
      contact_id: routerData.contact_id,
      phone: routerData.phone,
      channel_id: routerData.channel_id,
      content: welcomeMessage
    }
  }];
}

msgs.reverse();

const historyText = msgs.map(m => {
  const role = m.direction === 'in' ? 'USER' : 'ASSISTANT';
  return `${role}: ${m.content || ''}`;
}).join('\n\n');

const systemContent = `${routerData.system_prompt}\n\nRESTRISÇÕES IMPORTANTES (O QUE NUNCA FAZER):\n${routerData.negative_prompt}`;

const systemMessage = `${systemContent}\n\nCONVERSATION HISTORY:\n${historyText}`;

return [{
  json: {
    is_welcome: false,
    api_key: routerData.api_key,
    model: routerData.model,
    temperature: routerData.temperature,
    chatInput: routerData.user_message,
    systemMessage: systemMessage,
    contact_id: routerData.contact_id,
    phone: routerData.phone,
    channel_id: routerData.channel_id
  }
}];

const resp = $input.first().json;
const answer = resp.output || resp.text || resp.content || JSON.stringify(resp);
const inputData = $('Format Prompt & History').first().json;
return [{
  json: {
    contact_id: inputData.contact_id,
    phone: inputData.phone,
    channel_id: inputData.channel_id,
    content: answer
  }
}];

const evoResponse = $input.first().json;
const parseData = $('Is Media?').first().json;

// Check if there was an error in the previous node
if (evoResponse.error || !evoResponse.base64) {
  return [{ json: parseData }];
}

const base64Data = evoResponse.base64;
const mimeType = evoResponse.mimetype || parseData.mime_type;
const extension = mimeType.split('/')[1]?.split(';')[0] || 'bin';
const fileName = parseData.whatsapp_msg_id + '_' + parseData.content_type + '.' + (extension === 'ogg' ? 'ogg' : extension);

return [{
  json: {
    ...parseData,
    upload_base64: base64Data,
    upload_mime_type: mimeType,
    upload_file_name: fileName
  }
}];

const data = $('Process Base64 Upload').first().json;
const uploadResult = $('Upload Media to Supabase').first().json;

let publicUrl = null;
if (data.upload_file_name && !uploadResult.error) {
  publicUrl = "https://rjcuoxvutrrzknicyuev.supabase.co/storage/v1/object/public/media/" + data.upload_file_name;
}

return [{
  json: {
    event_type: data.event_type,
    whatsapp_msg_id: data.whatsapp_msg_id,
    phone: data.phone,
    contact_name: data.contact_name,
    direction: data.direction,
    content: data.content,
    content_type: data.content_type,
    media_url: publicUrl,
    mime_type: data.mime_type,
    timestamp: data.timestamp,
    instance: data.instance
  }
}];

